import{_ as a,c as e,o as s,a1 as r}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"进阶配置: 高级功能详解 | Antigravity-Manager","description":"学习 Antigravity-Manager 的进阶配置方法。掌握账号调度、模型路由、配额治理和监控统计等高级功能。","frontmatter":{"title":"进阶配置: 高级功能详解 | Antigravity-Manager","order":300,"sidebarTitle":"把系统升级到生产级","subtitle":"进阶配置: 高级功能详解","description":"学习 Antigravity-Manager 的进阶配置方法。掌握账号调度、模型路由、配额治理和监控统计等高级功能。"},"headers":[],"relativePath":"zh/lbjlaq/Antigravity-Manager/advanced/index.md","filePath":"zh/lbjlaq/Antigravity-Manager/advanced/index.md"}'),n={name:"zh/lbjlaq/Antigravity-Manager/advanced/index.md"};function d(o,t,i,l,p,c){return s(),e("div",null,[...t[0]||(t[0]=[r(`<h1 id="进阶配置" tabindex="-1">进阶配置 <a class="header-anchor" href="#进阶配置" aria-label="Permalink to &quot;进阶配置&quot;">​</a></h1><p>本章节深入讲解 Antigravity Tools 的高级功能：配置管理、安全策略、账号调度、模型路由、配额治理、监控统计，以及服务器部署方案。掌握这些内容后，你可以把 Antigravity Tools 从&quot;能用&quot;升级到&quot;好用、稳定、可运维&quot;。</p><h2 id="本章包含" tabindex="-1">本章包含 <a class="header-anchor" href="#本章包含" aria-label="Permalink to &quot;本章包含&quot;">​</a></h2><table tabindex="0"><thead><tr><th>教程</th><th>说明</th></tr></thead><tbody><tr><td><a href="./config/">配置全解</a></td><td>AppConfig/ProxyConfig 的完整字段、落盘位置与热更新语义</td></tr><tr><td><a href="./security/">安全与隐私</a></td><td><code>auth_mode</code>、<code>allow_lan_access</code> 与安全基线设计</td></tr><tr><td><a href="./scheduling/">高可用调度</a></td><td>轮换、固定账号、粘性会话与失败重试机制</td></tr><tr><td><a href="./model-router/">模型路由</a></td><td>自定义映射、通配符优先级与预设策略</td></tr><tr><td><a href="./quota/">配额治理</a></td><td>Quota Protection + Smart Warmup 的组合打法</td></tr><tr><td><a href="./monitoring/">Proxy Monitor</a></td><td>请求日志、筛选、详情还原与导出</td></tr><tr><td><a href="./token-stats/">Token Stats</a></td><td>成本视角的统计口径与图表解读</td></tr><tr><td><a href="./context-compression/">长会话稳定性</a></td><td>上下文压缩、签名缓存与工具结果压缩</td></tr><tr><td><a href="./system/">系统能力</a></td><td>多语言/主题/更新/开机自启/HTTP API Server</td></tr><tr><td><a href="./deployment/">服务器部署</a></td><td>Docker noVNC vs Headless Xvfb 选型与运维</td></tr></tbody></table><h2 id="学习路径建议" tabindex="-1">学习路径建议 <a class="header-anchor" href="#学习路径建议" aria-label="Permalink to &quot;学习路径建议&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">推荐顺序</p><p>本章内容较多，建议按以下模块分批学习：</p></div><p><strong>第一阶段：配置与安全（必学）</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>配置全解 → 安全与隐私</span></span>
<span class="line"><span>config      security</span></span></code></pre></div><p>先了解配置体系（哪些需要重启、哪些热更新），再学安全设置（尤其是暴露到局域网/公网时）。</p><p><strong>第二阶段：调度与路由（推荐）</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>高可用调度 → 模型路由</span></span>
<span class="line"><span>scheduling    model-router</span></span></code></pre></div><p>学会用最小账号数获得最大稳定性，再用模型路由屏蔽上游变化。</p><p><strong>第三阶段：配额与监控（按需）</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>配额治理 → Proxy Monitor → Token Stats</span></span>
<span class="line"><span>quota        monitoring      token-stats</span></span></code></pre></div><p>防止配额无感耗尽，把调用黑盒变成可观测系统，量化成本优化。</p><p><strong>第四阶段：稳定性与部署（进阶）</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>长会话稳定性 → 系统能力 → 服务器部署</span></span>
<span class="line"><span>context-compression  system    deployment</span></span></code></pre></div><p>解决长会话的隐性问题，让客户端更像产品，最后学服务器部署。</p><p><strong>快速选择</strong>：</p><table tabindex="0"><thead><tr><th>你的场景</th><th>推荐先看</th></tr></thead><tbody><tr><td>多账号轮换不稳定</td><td><a href="./scheduling/">高可用调度</a></td></tr><tr><td>想固定某个模型名</td><td><a href="./model-router/">模型路由</a></td></tr><tr><td>配额总是用完</td><td><a href="./quota/">配额治理</a></td></tr><tr><td>想看请求日志</td><td><a href="./monitoring/">Proxy Monitor</a></td></tr><tr><td>想统计 Token 消耗</td><td><a href="./token-stats/">Token Stats</a></td></tr><tr><td>长对话经常出错</td><td><a href="./context-compression/">长会话稳定性</a></td></tr><tr><td>要暴露到局域网</td><td><a href="./security/">安全与隐私</a></td></tr><tr><td>要部署到服务器</td><td><a href="./deployment/">服务器部署</a></td></tr></tbody></table><h2 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">开始前请确认</p><ul><li>已完成 <a href="./../start/">快速开始</a> 章节（至少完成安装、添加账号、启动反代）</li><li>已完成 <a href="./../platforms/">平台与集成</a> 中至少一个协议的接入（如 OpenAI 或 Anthropic）</li><li>本地反代已能正常响应请求</li></ul></div><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>学完本章节后，你可以继续学习：</p><ul><li><a href="./../faq/">常见问题</a>：遇到 401/404/429/流式中断等问题时的排查指南</li><li><a href="./../appendix/">附录</a>：端点速查表、数据模型、z.ai 能力边界等参考资料</li></ul>`,25)])])}const g=a(n,[["render",d]]);export{u as __pageData,g as default};
